import org.springframework.stereotype.Service;

/**
 * A service for generating user-related messages.
 */
@Service
public class MessageService {

    private static final String WELCOME_MESSAGE_TEMPLATE = "<h1>Welcome, %s!</h1>";

    /**
     * Generates a personalized HTML welcome message for a user.
     *
     * @param username The name of the user.
     * @return An HTML string containing the welcome message, with the username safely escaped to prevent XSS.
     */
    public String getWelcomeMessage(String username) {
        String safeUsername = htmlEncode(username);
        return String.format(WELCOME_MESSAGE_TEMPLATE, safeUsername);
    }

    /**
     * Escapes HTML special characters to mitigate cross‑site scripting (XSS) vulnerabilities.
     *
     * @param input the raw user input.
     * @return the HTML‑safe encoded string.
     */
    private String htmlEncode(String input) {
        if (input == null) {
            return "";
        }
        StringBuilder sb = new StringBuilder(input.length() + 16);
        for (char c : input.toCharArray()) {
            switch (c) {
                case '<':
                    sb.append("&lt;");
                    break;
                case '>':
                    sb.append("&gt;");
                    break;
                case '&':
                    sb.append("&amp;");
                    break;
                case '"':
                    sb.append("&quot;");
                    break;
                case '\'':
                    sb.append("&#x27;");
                    break;
                default:
                    sb.append(c);
                    break;
            }
        }
        return sb.toString();
    }
}

